import vex

from ag2 import GroupChat, GroupChatManager

# Initialize Vex client for Government workspace
vex_client = vex.Client(api_key="gov-agency-key", workspace="fedramp-moderate")

@vex_client.hook("ag2-government")
def audit_group_chat(message, sender, recipients):
    # Block classified data patterns
    if vex.classified_data.scan(message):
        return {"block": True, "reason": "CUI detected"}
    # Log for FedRAMP audit trail
    vex_client.log_event(
        "ag2_message",
        {
            "sender": sender.name,
            "content": message,
            "classification": vex.classification_level(message),
            "timestamp": "now"
        }
    )

# Register hook with AG2 group chat
manager = GroupChatManager(groupchat=groupchat, message_hook=vex_client.hook)

from vex.patterns import ConversationDriftDetector

@vex_client.hook("ag2-drift-protection")
def prevent_spiral(message, context, session_id):
    detector = ConversationDriftDetector(
        topic="national_security_policy",
        max_drift_score=0.3,
        session_id=session_id
    )

    drift_score = detector.analyze(message, context)
    if drift_score > 0.3:
        return {
            "block": True,
            "reason": f"Topic drift detected (score: {drift_score:.2f})",
            "redirect": "Please focus on authorized security policy discussion."
        }
    return {"allow": True}

from vex.security import CodeScanner

scanner = CodeScanner(standards=["NIST-800-53", "FedRAMP-High"])

@vex_client.hook("ag2-code-security")
def secure_code_execution(code_block, agent_name, execution_context):
    # Static analysis for malware patterns
    threats = scanner.scan(code_block)
    if threats:
        vex_client.alert(
            "MALICIOUS_CODE",
            {
                "agent": agent_name,
                "threats": threats,
                "code_sample": code_block[:200]
            }
        )
        return {"block": True, "reason": f"{len(threats)} threats detected"}

    # Dynamic sandbox execution
    result = vex.sandbox.execute(code_block, timeout=30)
    if result.status == "blocked":
        return {"block": True, "reason": "Sandbox violation"}

    return {"allow": True, "result": result.output}
